const body = items[0].json.body || items[0].json || {};
const isRegen = body.event === 'content_rejected' || body.mode === 'regenerate';
return [{
  json: {
    mode: isRegen ? 'regenerate' : (body.event === 'strategy_ready' ? 'from_strategy' : 'cadence'),
    campaign_id: body.campaign_id || null,
    content_item_id: body.content_item_id || null,
    rejection_reason: body.rejection_reason || null,
    strategy_id: body.strategy_id || null
  }
}];

const row = items[0].json;
if (!row || !row.campaign_id && !row.id) {
  return [{ json: { skip: true, reason: 'No campaign/strategy context' } }];
}
const isRegen = !!row.rejection_reason || !!$('Normalize Trigger').isExecuted && $('Normalize Trigger').item.json.mode === 'regenerate';
const rejection = $('Normalize Trigger').isExecuted ? $('Normalize Trigger').item.json.rejection_reason : null;
const campaign = {
  id: row.campaign_id || row.id,
  name: row.campaign_name,
  brief: row.brief,
  product_type: row.product_type,
  target_audience: row.target_audience,
  strategy: {
    id: row.strategy_id,
    positioning: row.positioning,
    key_messages: row.key_messages,
    channels: row.channels,
    posting_cadence: row.posting_cadence,
    content_pillars: row.content_pillars
  },
  regenerate: isRegen || !!rejection,
  previous_draft: isRegen || rejection ? {
    content_item_id: row.id,
    channel: row.channel,
    content_type: row.content_type,
    content_pillar: row.content_pillar,
    draft_copy: row.draft_copy,
    media_brief: row.media_brief,
    rejection_reason: rejection || row.rejection_reason
  } : null
};
if (!campaign.strategy.positioning) {
  return [{ json: { skip: true, reason: 'No strategy row — Agent 1 must run first', campaign_id: campaign.id } }];
}
return [{ json: { skip: false, campaign } }];

const raw = items[0].json.choices?.[0]?.message?.content || '';
let text = String(raw).trim();
if (text.startsWith('```')) text = text.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '');
const data = JSON.parse(text);
const list = Array.isArray(data) ? data : data.items;
if (!Array.isArray(list) || !list.length) throw new Error('No content items returned');
const campaign = $('Build LLM Context').item.json.campaign;
const parentId = campaign.previous_draft?.content_item_id || null;
return list.map((item) => ({
  json: {
    campaign_id: campaign.id,
    strategy_id: campaign.strategy.id,
    channel: String(item.channel || '').toLowerCase(),
    content_type: item.content_type || 'post',
    content_pillar: item.content_pillar || campaign.previous_draft?.content_pillar || null,
    draft_copy: item.draft_copy,
    media_brief: item.media_brief || null,
    scheduled_time: item.scheduled_time_suggestion || null,
    parent_item_id: parentId,
    status: 'pending_approval'
  }
}));

parameters.query:
INSERT INTO content_items (
  campaign_id, strategy_id, channel, content_type, content_pillar,
  draft_copy, media_brief, status, scheduled_time, parent_item_id
) VALUES (
  $1::uuid, $2::uuid, $3, $4, $5,
  $6, $7, 'pending_approval', $8::timestamptz, $9::uuid
)
RETURNING id, campaign_id, channel, status, created_at;
